// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.join;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

class LmdbLongHashSetTest {

	@Test
	void addContainsAndDeduplicatesAfterGrowth() {
		LmdbLongHashSet set = new LmdbLongHashSet(1);

		assertThat(set.add(0)).isTrue();
		assertThat(set.add(0)).isFalse();
		assertThat(set.contains(0)).isTrue();
		assertThat(set.size()).isEqualTo(1);

		for (long i = 1; i <= 10_000; i++) {
			assertThat(set.add(i << 7)).isTrue();
		}

		for (long i = 1; i <= 10_000; i++) {
			long id = i << 7;
			assertThat(set.contains(id)).isTrue();
			assertThat(set.add(id)).isFalse();
		}

		assertThat(set.contains(123_456_789L)).isFalse();
		assertThat(set.size()).isEqualTo(10_001);
	}

	@Test
	void clearAfterGrowthRemovesOldKeysAndAllowsReuse() {
		LmdbLongHashSet set = new LmdbLongHashSet(1);

		for (long i = 1; i <= 10_000; i++) {
			assertThat(set.add(i * 31)).isTrue();
		}

		set.clear();

		assertThat(set.size()).isZero();
		assertThat(set.contains(31)).isFalse();
		assertThat(set.contains(10_000L * 31)).isFalse();

		assertThat(set.add(0)).isTrue();
		for (long i = 20_001; i <= 21_000; i++) {
			assertThat(set.add(i * 31)).isTrue();
		}

		assertThat(set.contains(0)).isTrue();
		assertThat(set.contains(20_001L * 31)).isTrue();
		assertThat(set.contains(21_000L * 31)).isTrue();
		assertThat(set.contains(31)).isFalse();
		assertThat(set.size()).isEqualTo(1_001);

		set.clear();

		assertThat(set.size()).isZero();
		assertThat(set.contains(0)).isFalse();
		assertThat(set.contains(20_001L * 31)).isFalse();
	}
}
